/**
 * File Search Service Unit Tests
 * タスク3.2: Gemini File Search API統合のテスト
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';

// Mock environment variables
beforeEach(() => {
  process.env.GEMINI_API_KEY = 'test-api-key';
});

describe('FileSearchService', () => {
  describe('searchFiles', () => {
    it('should return top 3 results when successful', async () => {
      // このテストは実際のAPIを呼び出さず、モックデータを使用
      const { searchFiles } = await import('@/server/lib/gemini/file-search-service');

      const query = 'WMG2027の参加資格';
      const result = await searchFiles(query);

      expect(result.success).toBe(true);
      expect(result.results).toBeDefined();
      expect(result.results.length).toBeLessThanOrEqual(3);
    });

    it('should return fallback context when no results found', async () => {
      const { searchFiles } = await import('@/server/lib/gemini/file-search-service');

      const query = 'completely_nonexistent_query_12345';
      const result = await searchFiles(query);

      expect(result.success).toBe(true);
      // フォールバック時は空配列またはデフォルトコンテキストを返す
      expect(Array.isArray(result.results)).toBe(true);
    });

    it('should handle timeout gracefully', async () => {
      const { searchFiles } = await import('@/server/lib/gemini/file-search-service');

      // タイムアウトシミュレーション（実際のタイムアウトは5秒）
      // この場合、フォールバックコンテキストを返す
      const result = await searchFiles('test query', { timeout: 1 }); // 1msタイムアウト

      expect(result.success).toBe(true);
      expect(Array.isArray(result.results)).toBe(true);
    }, 10000);

    it('should extract source metadata correctly', async () => {
      const { searchFiles } = await import('@/server/lib/gemini/file-search-service');

      const query = 'test query';
      const result = await searchFiles(query);

      if (result.results.length > 0) {
        const firstResult = result.results[0];
        expect(firstResult).toHaveProperty('text');
        expect(firstResult).toHaveProperty('display_name');
        expect(firstResult).toHaveProperty('uri');
        expect(firstResult).toHaveProperty('source_type');
        expect(['qa', 'web']).toContain(firstResult.source_type);
      }
    });

    it('should include both QA and Web files in search', async () => {
      // manifestファイルの内容を確認
      const manifestJson = await import('@/../data/file-store-manifest.json');

      // File Search Store対応バージョンを確認
      expect(manifestJson.default.version).toBe('3.0.0');

      const qaFiles = manifestJson.default.files.filter(
        (f: { source_type: string }) => f.source_type === 'qa'
      );
      const webFiles = manifestJson.default.files.filter(
        (f: { source_type: string }) => f.source_type === 'web'
      );

      // Webファイルが存在することを確認（QAは現状0件の可能性あり）
      expect(webFiles.length).toBeGreaterThan(0);

      // ファイルが正しくフィルタリングされることを確認
      const allSearchableFiles = manifestJson.default.files.filter(
        (f: { source_type: string }) => f.source_type === 'qa' || f.source_type === 'web'
      );
      expect(allSearchableFiles.length).toBe(qaFiles.length + webFiles.length);
    });

    it('should use correct display names for different source types', async () => {
      const { searchFiles } = await import('@/server/lib/gemini/file-search-service');

      const query = 'WMG2027';
      const result = await searchFiles(query);

      if (result.results.length > 0) {
        result.results.forEach(item => {
          if (item.source_type === 'web') {
            // テスト環境ではAPI呼び出しなしでfallbackコンテキストが返される場合がある
            // 正常時は '公式サイト'、フォールバック時は '公式サイト案内'
            expect(['公式サイト', '公式サイト案内']).toContain(item.display_name);
            expect(item.uri).toContain('wmg2027.jp');
          } else if (item.source_type === 'qa') {
            expect(item.display_name).toBe('Q&Aデータ');
          }
        });
      }
    });

    it('should have correct fallback context without "fallback-context" string', async () => {
      const { searchFiles } = await import('@/server/lib/gemini/file-search-service');

      // 存在しないクエリでfallbackをトリガー
      const query = 'xyzabc_nonexistent_query_999999';
      const result = await searchFiles(query, { timeout: 100 });

      expect(result.success).toBe(true);
      expect(result.results.length).toBeGreaterThan(0);

      // fallback contextのdisplay_nameに"fallback-context"という文字列が含まれないことを確認
      result.results.forEach(item => {
        expect(item.display_name).not.toContain('fallback-context');
        expect(item.display_name).toBe('公式サイト案内');
      });
    });
  });
});


