/**
 * Manual RAG Test Script
 * RAG検索機能を手動でテストするスクリプト
 *
 * Usage:
 *   tsx scripts/test-rag-manual.ts
 */

import { searchFiles } from '../src/server/lib/gemini/file-search-service';

interface TestCase {
  id: string;
  description: string;
  query: string;
  expectedSourceType: 'qa' | 'web' | 'both';
  expectedKeywords?: string[];
}

const testCases: TestCase[] = [
  {
    id: 'T1-1',
    description: 'Q&Aデータからの回答（参加資格・年齢）',
    query: '参加資格は何歳からですか？',
    expectedSourceType: 'qa',
    expectedKeywords: ['歳', '年齢', '資格'],
  },
  {
    id: 'T1-2',
    description: 'Webコンテンツからの回答（開催場所）',
    query: '大会の開催場所はどこですか？',
    expectedSourceType: 'web',
    expectedKeywords: ['開催', '場所', '会場'],
  },
  {
    id: 'T1-3',
    description: '複合検索（WMG2027とは）',
    query: 'WMG2027とは何ですか？',
    expectedSourceType: 'both',
    expectedKeywords: ['ワールドマスターズゲームズ', 'WMG', '2027'],
  },
  {
    id: 'T2-1',
    description: 'エントリー方法',
    query: 'エントリー方法を教えてください',
    expectedSourceType: 'both',
    expectedKeywords: ['エントリー', '申込', '登録'],
  },
  {
    id: 'T3-1',
    description: '競技種目',
    query: 'どんな競技がありますか？',
    expectedSourceType: 'web',
    expectedKeywords: ['競技', '種目'],
  },
];

async function runTest(testCase: TestCase): Promise<void> {
  console.log(`\n${'='.repeat(80)}`);
  console.log(`Test Case: ${testCase.id} - ${testCase.description}`);
  console.log(`Query: "${testCase.query}"`);
  console.log(`Expected Source Type: ${testCase.expectedSourceType}`);
  console.log(`${'='.repeat(80)}\n`);

  try {
    const result = await searchFiles(testCase.query, { numResults: 3 });

    console.log(`✓ Success: ${result.success}`);
    console.log(`✓ Results Count: ${result.results.length}`);

    if (result.results.length === 0) {
      console.log('⚠️ WARNING: No results found (fallback context returned)');
    }

    result.results.forEach((item, index) => {
      console.log(`\nResult #${index + 1}:`);
      console.log(`  Display Name: ${item.display_name}`);
      console.log(`  Source Type: ${item.source_type}`);
      console.log(`  URI: ${item.uri}`);
      console.log(`  Original Question: ${item.original_question || 'N/A'}`);
      console.log(`  Text Preview: ${item.text.substring(0, 200)}...`);

      if (item.relevance) {
        console.log(`  Relevance: ${item.relevance}`);
      }
    });

    // Validation
    const sourceTypes = [...new Set(result.results.map(r => r.source_type))];
    console.log(`\n📊 Source Types Found: ${sourceTypes.join(', ')}`);

    if (testCase.expectedSourceType === 'qa' && !sourceTypes.includes('qa')) {
      console.log('❌ FAIL: Expected Q&A data but not found');
    } else if (testCase.expectedSourceType === 'web' && !sourceTypes.includes('web')) {
      console.log('❌ FAIL: Expected Web content but not found');
    } else if (testCase.expectedSourceType === 'both' && sourceTypes.length < 2) {
      console.log('⚠️ WARNING: Expected both Q&A and Web but only found one type');
    } else {
      console.log('✓ PASS: Source type matches expectation');
    }
  } catch (error) {
    console.error('❌ ERROR:', error);
  }
}

