/**
 * Gemini File Search Store API Helper
 * 新SDK(@google/genai)を使用したFile Search Store実装
 *
 * Migration:
 * - 旧: @google/generative-ai/server (GoogleAIFileManager) - 48時間制限
 * - 新: @google/genai (GoogleGenAI.fileSearchStores) - 永続化
 */

import { GoogleGenAI } from '@google/genai';
import fs from 'fs';
import path from 'path';

export interface FileMetadata {
  display_name: string;
  source_type: 'qa' | 'web';
  locale?: string;
  category?: string;
  url?: string; // Webページの元URL
}

export interface UploadResult {
  success: boolean;
  file_id?: string;
  file_search_store_name?: string;
  display_name?: string;
  mime_type?: string;
  error?: string;
}

export interface ManifestFile {
  file_id: string;
  file_search_store_name?: string;
  display_name: string;
  source_type: 'qa' | 'web';
  uploaded_at: string;
  locale?: string;
  category?: string;
  url?: string;
}

export interface Manifest {
  version: string;
  updated_at: string;
  file_search_store_name?: string;
  files: ManifestFile[];
}

// グローバルキャッシュ（同一実行中のストア名を保持）
let cachedStoreName: string | null = null;

// デフォルトのStore表示名（環境別に変更可能）
const DEFAULT_STORE_DISPLAY_NAME = 'wmg2027-ai-chatbot-store';

/**
 * APIエラーを分かりやすいメッセージに変換
 */
function formatApiError(error: unknown): string {
  const errorStr = error instanceof Error ? error.message : String(error);

  // JSONエラーレスポンスをパース
  try {
    const jsonMatch = errorStr.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const errorObj = JSON.parse(jsonMatch[0]);
      const code = errorObj.error?.code || errorObj.code;
      const status = errorObj.error?.status || errorObj.status;
      const message = errorObj.error?.message || errorObj.message;

      // HTTPステータスコードに基づくメッセージ
      switch (code) {
        case 400:
          return `リクエストエラー: ${message || 'ファイル形式またはサイズが不正です'}`;
        case 401:
          return 'API認証エラー: APIキーが無効または期限切れです';
        case 403:
          return 'アクセス拒否: このファイルまたはリソースへのアクセス権限がありません';
        case 404:
          return 'リソース未検出: 指定されたファイルまたはストアが見つかりません';
        case 429:
          return 'レート制限: APIリクエスト数の上限に達しました。しばらく待ってから再試行してください';
        case 500:
          return 'サーバー内部エラー: Gemini APIサーバーで問題が発生しました';
        case 503:
          return 'サービス一時停止: Gemini APIサーバーが一時的に利用できません。しばらく待ってから再試行してください';
        default:
          if (status) {
            return `${status} (${code}): ${message || 'APIエラーが発生しました'}`;
          }
      }
    }
  } catch {
    // JSONパース失敗時は元のメッセージを使用
  }

  // 一般的なエラーパターン
  if (errorStr.includes('ENOTFOUND') || errorStr.includes('ECONNREFUSED')) {
    return 'ネットワークエラー: Gemini APIサーバーに接続できません';
  }
  if (errorStr.includes('timeout') || errorStr.includes('ETIMEDOUT')) {
    return 'タイムアウト: リクエストがタイムアウトしました。ファイルサイズを確認してください';
  }
  if (errorStr.includes('ENOENT')) {
    return 'ファイルエラー: 指定されたファイルが見つかりません';
  }

  return errorStr;
}

/**
 * 環境変数からStore名を取得
 * FILE_SEARCH_STORE_NAME が設定されていればそれを使用
 */
function getStoreDisplayName(): string {
  // 環境変数でフルパス（fileSearchStores/xxx）が指定されている場合
  const envStoreName = process.env.FILE_SEARCH_STORE_NAME;
  if (envStoreName) {
    // フルパスからdisplayNameを推測（末尾のIDを除去）
    // 例: fileSearchStores/wmg2027-prod-xxx → wmg2027-prod-xxx は不明なので
    // 環境変数指定時は直接そのStoreを使用する
    console.log(`  📌 環境変数からStore名を使用: ${envStoreName}`);
    return envStoreName;
  }
  return DEFAULT_STORE_DISPLAY_NAME;
}

/**
 * File Search Storeを取得または作成（新SDK使用）
 *
 * 環境分離:
 * - FILE_SEARCH_STORE_NAME 環境変数でフルパスを指定可能
 * - 未設定時は DEFAULT_STORE_DISPLAY_NAME で検索/作成
 */
async function getOrCreateFileSearchStore(ai: GoogleGenAI, storeName?: string): Promise<string> {
  // キャッシュがあれば返す
  if (cachedStoreName) {
    console.log(`  ✓ キャッシュ済みFile Search Storeを使用: ${cachedStoreName}`);
    return cachedStoreName;
  }

  // 環境変数でフルパスが指定されている場合は直接使用
  const envStoreName = process.env.FILE_SEARCH_STORE_NAME;
  if (envStoreName && envStoreName.startsWith('fileSearchStores/')) {
    console.log(`  ✓ 環境変数で指定されたFile Search Storeを使用: ${envStoreName}`);
    cachedStoreName = envStoreName;
    return envStoreName;
  }

  // Store表示名を決定
  const displayName = storeName || getStoreDisplayName();

  try {
    // 既存のストアを検索
    console.log('  📋 既存のFile Search Storeを検索中...');
    const stores = await ai.fileSearchStores.list();

    for await (const store of stores) {
      if (store.displayName === displayName) {
        console.log(`  ✓ 既存のFile Search Storeを発見: ${store.name}`);
        cachedStoreName = store.name || null;
        return store.name!;
      }
    }

    // 新規作成
    console.log(`  🆕 新しいFile Search Storeを作成中: ${displayName}`);
    const newStore = await ai.fileSearchStores.create({
      config: { displayName: displayName },
    });

    console.log(`  ✓ File Search Store作成完了: ${newStore.name}`);
    cachedStoreName = newStore.name || null;
    return newStore.name!;
  } catch (error) {
    throw new Error(
      `File Search Store creation failed: ${error instanceof Error ? error.message : 'Unknown error'}`
    );
  }
}

/**
 * File Search Storeにファイルをアップロード（新SDK使用）
 *
 * 重要: File Search Storeは永続化されるため、48時間制限なし
 */
export async function uploadToFileStore(
  apiKey: string,
  jsonContent: any,
  metadata: FileMetadata
): Promise<UploadResult> {
  try {
    // 新SDKでGoogleGenAIクライアントを作成
    const ai = new GoogleGenAI({ apiKey });

    // File Search Storeを取得または作成
    const fileSearchStoreName = await getOrCreateFileSearchStore(ai);

    // 一時ファイルを作成（Vercelでは/tmpのみ書き込み可能）
    const isVercel = process.env.VERCEL === '1';
    const tempDir = isVercel ? '/tmp' : path.join(process.cwd(), 'temp');
    if (!isVercel && !fs.existsSync(tempDir)) {
      fs.mkdirSync(tempDir, { recursive: true });
    }

    const tempFilePath = path.join(tempDir, `${Date.now()}.txt`);

    // コンテンツをテキスト形式で保存
    const content =
      typeof jsonContent === 'string'
        ? jsonContent
        : typeof jsonContent === 'object' && jsonContent.content
          ? jsonContent.content
          : JSON.stringify(jsonContent, null, 2);
    fs.writeFileSync(tempFilePath, content);

    console.log(`  📤 ファイルをアップロード中: ${metadata.display_name}`);

    // File Search Store Upload API（新SDK）
    const operation = await ai.fileSearchStores.uploadToFileSearchStore({
      file: tempFilePath,
      fileSearchStoreName: fileSearchStoreName,
      config: {
        displayName: metadata.display_name,
        customMetadata: [
          { key: 'source_type', stringValue: metadata.source_type },
          ...(metadata.locale ? [{ key: 'locale', stringValue: metadata.locale }] : []),
          ...(metadata.category ? [{ key: 'category', stringValue: metadata.category }] : []),
          ...(metadata.url ? [{ key: 'url', stringValue: metadata.url }] : []),
        ],
      },
    });

    // 一時ファイルを削除
    fs.unlinkSync(tempFilePath);

    // オペレーション完了を待つ
    let result = operation;
    while (!result.done) {
      console.log('    ⏳ アップロード処理中...');
      await new Promise(resolve => setTimeout(resolve, 2000));

      // オペレーションの状態を確認（公式ドキュメント準拠: { operation: result }）
      result = await ai.operations.get({ operation: result });
    }

    if (result.error) {
      throw new Error(`Upload operation failed: ${JSON.stringify(result.error)}`);
    }

    // レスポンスからファイル情報を取得
    // File Search Store APIは documentName を返す（nameではない）
    const fileData = result.response as any;
    const documentName = fileData?.documentName || fileData?.name;

    console.log(`  ✅ アップロード完了: ${metadata.display_name} (${documentName})`);

    return {
      success: true,
      file_id: documentName || `uploaded-${Date.now()}`,
      file_search_store_name: fileSearchStoreName,
      display_name: metadata.display_name,
      mime_type: 'text/plain',
    };
  } catch (error) {
    const formattedError = formatApiError(error);
    console.error(`  ❌ アップロード失敗: ${metadata.display_name}`);
    console.error(`     エラー: ${formattedError}`);
    return {
      success: false,
      error: formattedError,
    };
  }
}

/**
 * manifestファイルを更新
 */
export function updateManifest(manifestPath: string, newFile: ManifestFile): void {
  let manifest: Manifest;

  if (fs.existsSync(manifestPath)) {
    manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf-8'));
  } else {
    manifest = {
      version: '3.0.0', // File Search Store（新SDK）対応バージョン
      updated_at: '',
      files: [],
    };
  }

  // File Search Store名を保持
  if (newFile.file_search_store_name && !manifest.file_search_store_name) {
    manifest.file_search_store_name = newFile.file_search_store_name;
  }

  // 既存のファイルを除外（同じdisplay_nameの場合は上書き）
  manifest.files = manifest.files.filter(f => f.display_name !== newFile.display_name);

  manifest.files.push(newFile);
  manifest.updated_at = new Date().toISOString();
  manifest.version = '3.0.0'; // バージョン更新

  fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, 2));
}

/**
 * File Search Store内のドキュメントを削除
 * Store Documents API使用（Files APIではなく）
 *
 * 注意: force=true パラメータを使用して非空ドキュメントも削除可能
 */
export async function deleteFromFileStore(apiKey: string, documentName: string): Promise<boolean> {
  try {
    // documentNameの形式: fileSearchStores/{store}/documents/{doc}
    const baseUrl = documentName.startsWith('fileSearchStores/')
      ? `https://generativelanguage.googleapis.com/v1beta/${documentName}`
      : `https://generativelanguage.googleapis.com/v1beta/${documentName}`;

    // force=true を追加して非空ドキュメントも削除可能に
    const url = `${baseUrl}?force=true`;

    const response = await fetch(url, {
      method: 'DELETE',
      headers: {
        'x-goog-api-key': apiKey,
      },
    });

    if (response.ok) {
      console.log(`  🗑️ ドキュメント削除完了: ${documentName}`);
      return true;
    } else {
      const error = await response.json();
      console.error(`  ❌ ドキュメント削除失敗: ${documentName}`, error);
      return false;
    }
  } catch (error) {
    console.error(`  ❌ ドキュメント削除失敗: ${documentName}`, error);
    return false;
  }
}

/**
 * File Search Store内のドキュメント一覧を取得
 * Store Documents API使用（Files APIではなく）
 */
export async function listFilesInStore(
  apiKey: string,
  fileSearchStoreName: string
): Promise<any[]> {
  try {
    // fileSearchStoreName形式: fileSearchStores/{storeName}
    const storeName = fileSearchStoreName.replace('fileSearchStores/', '');
    const allDocuments: any[] = [];
    let pageToken: string | undefined;

    do {
      const url = new URL(
        `https://generativelanguage.googleapis.com/v1beta/fileSearchStores/${storeName}/documents`
      );
      url.searchParams.set('pageSize', '20'); // max 20
      if (pageToken) {
        url.searchParams.set('pageToken', pageToken);
      }

      const response = await fetch(url.toString(), {
        method: 'GET',
        headers: {
          'x-goog-api-key': apiKey,
        },
      });

      if (!response.ok) {
        const error = await response.json();
        console.error('  ❌ ドキュメント一覧取得失敗:', error);
        return allDocuments;
      }

      const data = await response.json();

      if (data.documents) {
        allDocuments.push(...data.documents);
      }

      pageToken = data.nextPageToken;
    } while (pageToken);

    return allDocuments;
  } catch (error) {
    console.error('  ❌ ドキュメント一覧取得失敗:', error);
    return [];
  }
}

// ========================================
// 重複検出・削除関連の関数
// ========================================

/**
 * URLに基づいてFile Search Store内の既存ドキュメントを検索
 * customMetadataのurlフィールドで照合
 *
 * @returns 見つかったドキュメントのname（複数の場合は配列で返す）
 */
export async function findDocumentsByUrl(
  apiKey: string,
  fileSearchStoreName: string,
  url: string
): Promise<string[]> {
  try {
    const documents = await listFilesInStore(apiKey, fileSearchStoreName);
    const matchingDocs: string[] = [];

    for (const doc of documents) {
      // customMetadataからurlを取得
      const urlMeta = doc.customMetadata?.find(
        (m: { key: string; stringValue?: string }) => m.key === 'url'
      );

      if (urlMeta?.stringValue === url) {
        matchingDocs.push(doc.name);
      }
    }

    if (matchingDocs.length > 0) {
      console.log(`  🔍 URL "${url}" に一致するドキュメント: ${matchingDocs.length}件`);
    }

    return matchingDocs;
  } catch (error) {
    console.error('  ❌ ドキュメント検索失敗:', error);
    return [];
  }
}

/**
 * displayNameに基づいてFile Search Store内の既存ドキュメントを検索
 * チャンクファイル（_partXofY）も含めて検索
 *
 * @returns 見つかったドキュメントのname配列
 */
export async function findDocumentsByDisplayName(
  apiKey: string,
  fileSearchStoreName: string,
  displayName: string
): Promise<string[]> {
  try {
    const documents = await listFilesInStore(apiKey, fileSearchStoreName);
    const matchingDocs: string[] = [];
    const baseName = getBaseFileName(displayName);

    for (const doc of documents) {
      const docDisplayName = doc.displayName || '';
      const docBaseName = getBaseFileName(docDisplayName);

      // 完全一致またはチャンクファイルのベース名が一致
      if (docDisplayName === displayName || docBaseName === baseName) {
        matchingDocs.push(doc.name);
      }
    }

    if (matchingDocs.length > 0) {
      console.log(
        `  🔍 displayName "${displayName}" に一致するドキュメント: ${matchingDocs.length}件`
      );
    }

    return matchingDocs;
  } catch (error) {
    console.error('  ❌ ドキュメント検索失敗:', error);
    return [];
  }
}

/**
 * URLに基づいて既存ドキュメントを削除（重複防止用）
 * チャンクファイルも含めて削除
 *
 * @returns 削除したドキュメント数
 */
export async function deleteDocumentsByUrl(
  apiKey: string,
  fileSearchStoreName: string,
  url: string
): Promise<number> {
  const documentNames = await findDocumentsByUrl(apiKey, fileSearchStoreName, url);

  if (documentNames.length === 0) {
    return 0;
  }

  console.log(`  🗑️ 重複ドキュメントを削除中: ${documentNames.length}件`);

  let deletedCount = 0;
  for (const docName of documentNames) {
    const success = await deleteFromFileStore(apiKey, docName);
    if (success) {
      deletedCount++;
    }
  }

  console.log(`  ✅ 削除完了: ${deletedCount}/${documentNames.length}件`);
  return deletedCount;
}

/**
 * displayNameに基づいて既存ドキュメントを削除（重複防止用）
 * チャンクファイルも含めて削除
 *
 * @returns 削除したドキュメント数
 */
export async function deleteDocumentsByDisplayName(
  apiKey: string,
  fileSearchStoreName: string,
  displayName: string
): Promise<number> {
  const documentNames = await findDocumentsByDisplayName(apiKey, fileSearchStoreName, displayName);

  if (documentNames.length === 0) {
    return 0;
  }

  console.log(`  🗑️ 重複ドキュメントを削除中: ${documentNames.length}件`);

  let deletedCount = 0;
  for (const docName of documentNames) {
    const success = await deleteFromFileStore(apiKey, docName);
    if (success) {
      deletedCount++;
    }
  }

  console.log(`  ✅ 削除完了: ${deletedCount}/${documentNames.length}件`);
  return deletedCount;
}

// ========================================
// チャンキング関連の定数と関数
// ========================================

/** チャンク分割のサイズ閾値（100KB以上で分割） */
export const CHUNK_SIZE_THRESHOLD = 100 * 1024; // 100KB

/** 1チャンクの最大サイズ */
export const MAX_CHUNK_SIZE = 80 * 1024; // 80KB

/** チャンクファイル名のパターン */
export const CHUNK_PATTERN = /_part(\d+)of(\d+)$/;

/**
 * コンテンツサイズをKB単位で取得
 */
export function getContentSizeKB(content: string): number {
  return Buffer.byteLength(content, 'utf-8') / 1024;
}

/**
 * コンテンツがチャンキングを必要とするか判定
 */
export function shouldChunkContent(content: string): boolean {
  return Buffer.byteLength(content, 'utf-8') > CHUNK_SIZE_THRESHOLD;
}

/**
 * ファイル名がチャンク形式かどうか判定
 */
export function isChunkedFile(displayName: string): boolean {
  return CHUNK_PATTERN.test(displayName);
}

/**
 * チャンクファイル名からベース名を取得
 */
export function getBaseFileName(displayName: string): string {
  return displayName.replace(CHUNK_PATTERN, '');
}

/**
 * チャンクファイル名からパート情報を取得
 */
export function getChunkInfo(
  displayName: string
): { partNumber: number; totalParts: number } | null {
  const match = displayName.match(CHUNK_PATTERN);
  if (!match) return null;
  return {
    partNumber: parseInt(match[1], 10),
    totalParts: parseInt(match[2], 10),
  };
}

/**
 * コンテンツをチャンクに分割
 */
export function splitContentIntoChunks(
  content: string,
  maxBytes: number = MAX_CHUNK_SIZE
): string[] {
  const chunks: string[] = [];
  const lines = content.split('\n');
  let currentChunk = '';

  for (const line of lines) {
    const testChunk = currentChunk ? `${currentChunk}\n${line}` : line;
    if (Buffer.byteLength(testChunk, 'utf-8') > maxBytes && currentChunk) {
      chunks.push(currentChunk);
      currentChunk = line;
    } else {
      currentChunk = testChunk;
    }
  }

  if (currentChunk) {
    chunks.push(currentChunk);
  }

  return chunks;
}

export interface ChunkedUploadResult {
  success: boolean;
  chunked: boolean;
  totalChunks: number;
  successfulChunks: number;
  results: UploadResult[];
  error?: string;
}

/**
 * 大きなファイルを分割してアップロード
 */
export async function uploadToFileStoreWithChunking(
  apiKey: string,
  content: string,
  metadata: FileMetadata
): Promise<ChunkedUploadResult> {
  const needsChunking = shouldChunkContent(content);

  if (!needsChunking) {
    // チャンキング不要の場合は通常アップロード
    const result = await uploadToFileStore(apiKey, content, metadata);
    return {
      success: result.success,
      chunked: false,
      totalChunks: 1,
      successfulChunks: result.success ? 1 : 0,
      results: [result],
      error: result.error,
    };
  }

  // チャンクに分割
  const chunks = splitContentIntoChunks(content);
  const totalChunks = chunks.length;
  const results: UploadResult[] = [];

  console.log(`  📦 ファイルを${totalChunks}個のチャンクに分割してアップロード`);

  for (let i = 0; i < chunks.length; i++) {
    const chunkMetadata: FileMetadata = {
      ...metadata,
      display_name: `${metadata.display_name}_part${i + 1}of${totalChunks}`,
    };

    console.log(`  📤 チャンク ${i + 1}/${totalChunks} をアップロード中...`);
    const result = await uploadToFileStore(apiKey, chunks[i], chunkMetadata);
    results.push(result);

    // レート制限対策: チャンク間に少し待機
    if (i < chunks.length - 1) {
      await new Promise(resolve => setTimeout(resolve, 1000));
    }
  }

  const successfulChunks = results.filter(r => r.success).length;

  return {
    success: successfulChunks === totalChunks,
    chunked: true,
    totalChunks,
    successfulChunks,
    results,
    error:
      successfulChunks < totalChunks
        ? `${totalChunks - successfulChunks}個のチャンクがアップロードに失敗しました`
        : undefined,
  };
}

