#!/usr/bin/env tsx
/**
 * Web Content Upload CLI
 * 外部Webコンテンツアップロード用CLIスクリプト
 *
 * 使用方法:
 * npm run upload:web
 */

import path from 'path';
import fs from 'fs';
import { crawlUrl } from './lib/web-crawler';
import { uploadToFileStore, updateManifest, type ManifestFile } from './lib/file-uploader';

const MANIFEST_PATH = path.join(process.cwd(), 'data/file-store-manifest.json');
const URLS_FILE = path.join(process.cwd(), 'data/crawl-urls.csv');

interface UrlEntry {
  url: string;
  category: string;
  locale: string;
}

/**
 * CSVファイルからURL一覧を読み込み
 */
function loadUrls(filePath: string): UrlEntry[] {
  if (!fs.existsSync(filePath)) {
    console.error(`❌ エラー: ${filePath} が見つかりません`);
    return [];
  }

  const content = fs.readFileSync(filePath, 'utf-8');
  const lines = content.split('\n').filter(line => line.trim());

  // ヘッダー行をスキップ
  const entries: UrlEntry[] = [];
  for (let i = 1; i < lines.length; i++) {
    const parts = lines[i].split(',').map(p => p.trim());
    if (parts.length >= 3) {
      entries.push({
        url: parts[0],
        category: parts[1],
        locale: parts[2],
      });
    }
  }

  return entries;
}

async function main() {
  console.log('🚀 外部Webコンテンツアップロード開始\n');

  const apiKey = process.env.GEMINI_API_KEY;
  if (!apiKey) {
    console.error('❌ エラー: GEMINI_API_KEY環境変数が設定されていません');
    process.exit(1);
  }

  const urls = loadUrls(URLS_FILE);
  if (urls.length === 0) {
    console.log('⚠️  クローリング対象URLが見つかりませんでした');
    console.log(`   ${URLS_FILE} を作成してURLを追加してください`);
    console.log('   フォーマット: url,category,locale');
    process.exit(0);
  }

  console.log(`📄 ${urls.length}件のURLを処理します\n`);

  let successCount = 0;
  let errorCount = 0;

  for (const entry of urls) {
    console.log(`🌐 処理中: ${entry.url}`);

    // クローリング
    console.log('  - HTML取得中...');
    const crawlResult = await crawlUrl(entry.url);

    if (!crawlResult.success) {
      console.error(`  ❌ クローリングエラー: ${crawlResult.error}`);
      errorCount++;
      continue;
    }

    console.log(`  ✓ Markdown変換完了（${crawlResult.markdown!.length}文字）`);

    // Gemini File Storeへアップロード
    console.log('  - Gemini File Storeへアップロード中...');

    const displayName = `web-${new URL(entry.url).hostname}-${Date.now()}.md`;

    const uploadResult = await uploadToFileStore(apiKey, crawlResult.markdown, {
      display_name: displayName,
      source_type: 'web',
      locale: entry.locale,
      category: entry.category,
      url: entry.url, // URLをメタデータに追加
    });

    if (!uploadResult.success) {
      console.error(`  ❌ アップロードエラー: ${uploadResult.error}`);
      errorCount++;
      continue;
    }

    console.log(`  ✓ アップロード完了: ${uploadResult.file_id}`);

    // Manifest更新
    const manifestFile: ManifestFile = {
      file_id: uploadResult.file_id!,
      file_search_store_name: uploadResult.file_search_store_name,
      display_name: uploadResult.display_name!,
      source_type: 'web',
      uploaded_at: new Date().toISOString(),
      locale: entry.locale,
      category: entry.category,
      url: entry.url, // 元のページURLを保存
    };

    updateManifest(MANIFEST_PATH, manifestFile);
    console.log('  ✓ Manifest更新完了\n');

    successCount++;
  }

  console.log(`\n✅ 処理完了: 成功 ${successCount}件、エラー ${errorCount}件`);
}

main().catch(error => {
  console.error('❌ 予期しないエラー:', error);
  process.exit(1);
});


